"""Launch Interceptor Program implementation per Knight & Leveson (1986).
"""
from __future__ import annotations

import math
from typing import Dict, List, Sequence, Tuple

PI = 3.1415926535
SIG_DIGITS = 6


def _round_to_significant_digits(value: float, digits: int = SIG_DIGITS) -> float:
    if value == 0.0:
        return 0.0
    magnitude = math.floor(math.log10(abs(value)))
    factor = 10 ** (digits - 1 - magnitude)
    return round(value * factor) / factor


def realcompare(a: float, b: float) -> str:
    ra = _round_to_significant_digits(a)
    rb = _round_to_significant_digits(b)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def real_lt(a: float, b: float) -> bool:
    return realcompare(a, b) == "LT"


def real_gt(a: float, b: float) -> bool:
    return realcompare(a, b) == "GT"


def real_eq(a: float, b: float) -> bool:
    return realcompare(a, b) == "EQ"


def real_le(a: float, b: float) -> bool:
    return not real_gt(a, b)


def real_ge(a: float, b: float) -> bool:
    return not real_lt(a, b)


Point = Tuple[float, float]


def _point_at(idx: int, x: Sequence[float], y: Sequence[float]) -> Point:
    return (x[idx], y[idx])


def _distance(p1: Point, p2: Point) -> float:
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def _triangle_area(p1: Point, p2: Point, p3: Point) -> float:
    return abs(
        (p1[0] * (p2[1] - p3[1])
         + p2[0] * (p3[1] - p1[1])
         + p3[0] * (p1[1] - p2[1])) / 2.0
    )


def _angle_at_vertex(p1: Point, vertex: Point, p3: Point) -> float | None:
    v1x = p1[0] - vertex[0]
    v1y = p1[1] - vertex[1]
    v2x = p3[0] - vertex[0]
    v2y = p3[1] - vertex[1]
    len1 = math.hypot(v1x, v1y)
    len2 = math.hypot(v2x, v2y)
    if real_eq(len1, 0.0) or real_eq(len2, 0.0):
        return None
    dot = v1x * v2x + v1y * v2y
    cos_theta = dot / (len1 * len2)
    cos_theta = max(min(cos_theta, 1.0), -1.0)
    return math.acos(cos_theta)


def _minimal_circle_radius(p1: Point, p2: Point, p3: Point) -> float:
    a = _distance(p2, p3)
    b = _distance(p1, p3)
    c = _distance(p1, p2)
    longest = max(a, b, c)
    area = _triangle_area(p1, p2, p3)
    if real_eq(area, 0.0):
        return longest / 2.0
    return (a * b * c) / (4.0 * area)


def _quadrant(point: Point) -> int:
    x, y = point
    if real_ge(x, 0.0) and real_ge(y, 0.0):
        return 1
    if real_lt(x, 0.0) and real_ge(y, 0.0):
        return 2
    if real_lt(y, 0.0):
        if real_lt(x, 0.0):
            return 3
        if real_eq(x, 0.0):
            return 3
        return 4
    if real_eq(x, 0.0):
        return 1
    return 4


def _distance_point_to_line(p: Point, a: Point, b: Point) -> float:
    if real_eq(_distance(a, b), 0.0):
        return _distance(p, a)
    dx = b[0] - a[0]
    dy = b[1] - a[1]
    numerator = abs(dy * (p[0] - a[0]) - dx * (p[1] - a[1]))
    denom = math.hypot(dx, dy)
    return numerator / denom


def _evaluate_cmv(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    parameters: Dict[str, float],
) -> List[bool]:
    cmv = [False] * 15

    length1 = parameters["LENGTH1"]
    radius1 = parameters["RADIUS1"]
    epsilon = parameters["EPSILON"]
    area1 = parameters["AREA1"]
    q_pts = parameters["Q_PTS"]
    quads = parameters["QUADS"]
    dist_limit = parameters["DIST"]
    n_pts = parameters["N_PTS"]
    k_pts = parameters["K_PTS"]
    a_pts = parameters["A_PTS"]
    b_pts = parameters["B_PTS"]
    c_pts = parameters["C_PTS"]
    d_pts = parameters["D_PTS"]
    e_pts = parameters["E_PTS"]
    f_pts = parameters["F_PTS"]
    g_pts = parameters["G_PTS"]
    length2 = parameters["LENGTH2"]
    radius2 = parameters["RADIUS2"]
    area2 = parameters["AREA2"]

    points = [_point_at(i, x, y) for i in range(numpoints)]

    # LIC 1
    for i in range(numpoints - 1):
        if real_gt(_distance(points[i], points[i + 1]), length1):
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        radius = _minimal_circle_radius(points[i], points[i + 1], points[i + 2])
        if real_gt(radius, radius1):
            cmv[1] = True
            break

    # LIC 3
    lower_bound = PI - epsilon
    upper_bound = PI + epsilon
    for i in range(numpoints - 2):
        angle = _angle_at_vertex(points[i], points[i + 1], points[i + 2])
        if angle is None:
            continue
        if real_lt(angle, lower_bound) or real_gt(angle, upper_bound):
            cmv[2] = True
            break

    # LIC 4
    for i in range(numpoints - 2):
        if real_gt(_triangle_area(points[i], points[i + 1], points[i + 2]), area1):
            cmv[3] = True
            break

    # LIC 5
    if q_pts <= numpoints:
        for i in range(numpoints - q_pts + 1):
            quads_present = set()
            for j in range(i, i + q_pts):
                quads_present.add(_quadrant(points[j]))
            if len(quads_present) > quads:
                cmv[4] = True
                break

    # LIC 6
    for i in range(numpoints - 1):
        if real_lt(points[i + 1][0] - points[i][0], 0.0):
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3 and n_pts <= numpoints:
        window = n_pts
        for i in range(numpoints - window + 1):
            start = points[i]
            end = points[i + window - 1]
            same = real_eq(start[0], end[0]) and real_eq(start[1], end[1])
            for j in range(i, i + window):
                if same:
                    distance = _distance(points[j], start)
                else:
                    distance = _distance_point_to_line(points[j], start, end)
                if real_gt(distance, dist_limit):
                    cmv[6] = True
                    break
            if cmv[6]:
                break

    # LIC 8
    if numpoints >= 3:
        steps = numpoints - k_pts - 1
        for i in range(max(0, steps)):
            j = i + k_pts + 1
            if real_gt(_distance(points[i], points[j]), length1):
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        limit = numpoints - a_pts - b_pts - 2
        for i in range(max(0, limit)):
            j = i + a_pts + 1
            k = j + b_pts + 1
            radius = _minimal_circle_radius(points[i], points[j], points[k])
            if real_gt(radius, radius1):
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        limit = numpoints - c_pts - d_pts - 2
        lower = PI - epsilon
        upper = PI + epsilon
        for i in range(max(0, limit)):
            j = i + c_pts + 1
            k = j + d_pts + 1
            angle = _angle_at_vertex(points[i], points[j], points[k])
            if angle is None:
                continue
            if real_lt(angle, lower) or real_gt(angle, upper):
                cmv[9] = True
                break

    # LIC 11
    if numpoints >= 5:
        limit = numpoints - e_pts - f_pts - 2
        for i in range(max(0, limit)):
            j = i + e_pts + 1
            k = j + f_pts + 1
            if real_gt(_triangle_area(points[i], points[j], points[k]), area1):
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        steps = numpoints - g_pts - 1
        for i in range(max(0, steps)):
            j = i + g_pts + 1
            if real_lt(points[j][0] - points[i][0], 0.0):
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        steps = numpoints - k_pts - 1
        exists_gt = False
        exists_lt = False
        for i in range(max(0, steps)):
            j = i + k_pts + 1
            distance = _distance(points[i], points[j])
            if not exists_gt and real_gt(distance, length1):
                exists_gt = True
            if not exists_lt and real_lt(distance, length2):
                exists_lt = True
            if exists_gt and exists_lt:
                cmv[12] = True
                break

    # LIC 14
    if numpoints >= 5:
        limit = numpoints - a_pts - b_pts - 2
        exists_gt = False
        exists_le = False
        for i in range(max(0, limit)):
            j = i + a_pts + 1
            k = j + b_pts + 1
            radius = _minimal_circle_radius(points[i], points[j], points[k])
            if not exists_gt and real_gt(radius, radius1):
                exists_gt = True
            if not exists_le and real_le(radius, radius2):
                exists_le = True
            if exists_gt and exists_le:
                cmv[13] = True
                break

    # LIC 15
    if numpoints >= 5:
        limit = numpoints - e_pts - f_pts - 2
        exists_gt = False
        exists_lt = False
        for i in range(max(0, limit)):
            j = i + e_pts + 1
            k = j + f_pts + 1
            area = _triangle_area(points[i], points[j], points[k])
            if not exists_gt and real_gt(area, area1):
                exists_gt = True
            if not exists_lt and real_lt(area, area2):
                exists_lt = True
            if exists_gt and exists_lt:
                cmv[14] = True
                break

    return cmv


def _build_pum(cmv: Sequence[bool], lcm: Sequence[Sequence[str]], pum_diag: Sequence[bool]) -> List[List[bool]]:
    size = len(cmv)
    pum = [[False] * size for _ in range(size)]
    for i in range(size):
        for j in range(size):
            if i == j:
                pum[i][j] = bool(pum_diag[i])
                continue
            connector = lcm[i][j]
            if connector == "NOTUSED":
                pum[i][j] = True
            elif connector == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif connector == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                raise ValueError(f"Unknown connector {connector!r} at ({i}, {j})")
    return pum


def _build_fuv(pum: Sequence[Sequence[bool]]) -> List[bool]:
    size = len(pum)
    fuv = [False] * size
    for i in range(size):
        if not pum[i][i]:
            fuv[i] = True
            continue
        row_all_true = all(pum[i][j] for j in range(size))
        fuv[i] = row_all_true
    return fuv


def decide(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    parameters: Dict[str, float],
    lcm: Sequence[Sequence[str]],
    pum_diag: Sequence[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    cmv = _evaluate_cmv(numpoints, x, y, parameters)
    pum = _build_pum(cmv, lcm, pum_diag)
    fuv = _build_fuv(pum)
    launch = all(fuv)
    return cmv, pum, fuv, launch
